import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function DriverRoute() {
  const { id } = useParams();

  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/emergency/all"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

  const markCompleted = async () => {
    try {
      await axios.put(
        `http://localhost:3000/api/driver/completed/${id}`
      );

      alert("Task Completed");

      navigate("/driver-dashboard");
    } catch (error) {
      console.log(error);
    }
  };

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center">
        Loading...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#4CBB17]/10 p-8">
      <div className="max-w-3xl mx-auto bg-white rounded-3xl shadow-xl p-8">

        <h1 className="text-4xl font-bold text-green-900 mb-8">
          Route Details
        </h1>

        <div className="space-y-4">

          <h2 className="text-2xl font-bold">
            📍 {task.location?.location}
          </h2>

          <p>
            Latitude :
            <span className="font-semibold">
              {" "}
              {task.location?.latitude}
            </span>
          </p>

          <p>
            Longitude :
            <span className="font-semibold">
              {" "}
              {task.location?.longitude}
            </span>
          </p>

          <a
            href={`https://www.google.com/maps?q=${task.location?.latitude},${task.location?.longitude}`}
            target="_blank"
            rel="noreferrer"
            className="inline-block bg-blue-600 text-white px-6 py-3 rounded-xl"
          >
            Open Location
          </a>

          <hr />

          {task.arrivedAt && (
            <div className="bg-yellow-100 p-4 rounded-xl">
              <p className="font-bold">
                Arrived Time :
              </p>

              <p>
                {new Date(task.arrivedAt).toLocaleString()}
              </p>
            </div>
          )}

          {task.completedAt && (
            <div className="bg-green-100 p-4 rounded-xl">
              <p className="font-bold">
                Completed Time :
              </p>

              <p>
                {new Date(task.completedAt).toLocaleString()}
              </p>
            </div>
          )}

          <div className="flex gap-4 mt-6">

            {task.status === "Scheduled" && (
              <button
                onClick={markArrived}
                className="bg-yellow-500 text-white px-8 py-3 rounded-xl"
              >
                Arrived
              </button>
            )}

            {task.status === "Arrived" && (
              <button
                onClick={markCompleted}
                className="bg-green-600 text-white px-8 py-3 rounded-xl"
              >
                Completed
              </button>
            )}

          </div>

        </div>
      </div>
    </div>
  );
}
